/// Optional sub-condition meta-data appended after the variant body.
/// Per the recipe: dispatcher slot 19 (`+0x98`) reads a 1-byte presence flag;
/// if non-zero, reads a 24-byte sub-object via 0x14b933930:
/// CString + u64 + u8 + u8 + u8.
#[derive(Debug)]
pub struct ConditionDataOptionData<'a> {
    pub label: CString<'a>,
    pub qword_a: u64,
    pub byte_b: u8,
    pub byte_c: u8,
    pub byte_d: u8,
}

impl<'a> ConditionDataOptionData<'a> {
    pub fn read_from(data: &'a [u8], offset: &mut usize) -> io::Result<Self> {
        let label = CString::read_from(data, offset)?;
        let qword_a = u64::read_from(data, offset)?;
        let byte_b = u8::read_from(data, offset)?;
        let byte_c = u8::read_from(data, offset)?;
        let byte_d = u8::read_from(data, offset)?;
        Ok(Self { label, qword_a, byte_b, byte_c, byte_d })
    }
    pub fn write_to(&self, w: &mut dyn Write) -> io::Result<()> {
        self.label.write_to(w)?;
        self.qword_a.write_to(w)?;
        self.byte_b.write_to(w)?;
        self.byte_c.write_to(w)?;
        self.byte_d.write_to(w)?;
        Ok(())
    }
    pub fn to_json_dict(&self) -> Map<String, Value> {
        let mut m = Map::new();
        m.insert("label".into(), self.label.to_json_value());
        m.insert("qword_a".into(), self.qword_a.to_json_value());
        m.insert("byte_b".into(), self.byte_b.to_json_value());
        m.insert("byte_c".into(), self.byte_c.to_json_value());
        m.insert("byte_d".into(), self.byte_d.to_json_value());
        m
    }
    pub fn write_from_json_dict(w: &mut Vec<u8>, obj: &Map<String, Value>) -> io::Result<()> {
        <CString as WriteJsonValue>::write_from_json(w, json_get_field(obj, "label")?)?;
        <u64 as WriteJsonValue>::write_from_json(w, json_get_field(obj, "qword_a")?)?;
        <u8 as WriteJsonValue>::write_from_json(w, json_get_field(obj, "byte_b")?)?;
        <u8 as WriteJsonValue>::write_from_json(w, json_get_field(obj, "byte_c")?)?;
        <u8 as WriteJsonValue>::write_from_json(w, json_get_field(obj, "byte_d")?)?;
        Ok(())
    }
}

/// Returns `true` if the given tag's variant skips reading the
/// `[u8 option_present][optional ConditionDataOptionData]` block.
///
/// ## Failure histogram (from `interaction_info::diag_raw_entries`,
/// captured 2026-04-30):
///
/// Current state — `n=0` Raw entries on interaction_info (100%
/// decoded, 363 of 363); condition_info 8920/8934 = 99.84%.
///
/// Remaining 14 Raw entries are confirmed source-data truncation
/// (not parser bugs): 7×272 (sub_tag bodies cut short), 3×372
/// (blob_len=4, u16 body needs 2 but only 1 byte remains), 1×9
/// (blob too short for u64), 1×31 (truncated), 1×286 (BinaryOpB
/// right-child absent), 1×287 (3 bytes for u32 body). Unfixable
/// without a corrected source dump.
///
/// Anti-disasm-family tags 54 and 214 were resolved via the **Mac
/// binary** (CrimsonDesert_Steam.app), where the vtables are not
/// stripped. Itanium ABI vtable layout has TWO destructor slots vs
/// MSVC's one, so vfn[16]=writer and vfn[17]=reader on Mac (vs
/// vfn[16]=reader on Win). Verified against tag 7 (GetItemCount)
/// where the Win-known body matched Mac's vfn[17].
///
/// Already-fixed since the n=101 regression peak:
///   tag 7   (GetItemCount)      — added trailing u16 via `08b7afc`
///   tag 29  (CheckMoneyForBuyingStock) — downgraded to unit via `584f79c`
///   tag 54  (CheckCurrentEquipType_OrTag54) — Mac vfn[17] = `0x100FBEB78`
///                                  reads 2× u32 → TwoU32BodyPayload
///   tag 99  (CheckAllyType)     — removed from skip-list via `5922251`
///   tag 116 (CatchTag)          — added OneCStringBodyPayload via `4469883`
///   tag 135 (CheckTargetToPushInventory) — added 1-byte body, KEPT in
///                                  skip-list via `93cc34d`; cleared all
///                                  18 entries
///   tag 174 (CheckRider)        — restored 1-byte body via `8f01078`
///   tag 214 (CheckExistStealItem) — Mac vfn[17] = `0x100FF106C`,
///                                  delegates to `sub_10101FB50`
///                                  (CArray<u16> reader) → ItemGroupKey
///                                  list. New `CheckExistStealItemPayload`.
///   tag 358 (CheckMercenaryType)— added OneByteBodyPayload via `147fd7f`
///   tag 360 (CheckTargetDropListToPushInventory) — 1-byte body via `2102303`
///   tag 370 (CheckOwnershipState) — 1-byte body, KEPT in skip-list via `41bc97f`
///   tag 393 (CheckAccompanyType)— added 1-byte body via `d91d961`
///   tag 19/27 (CheckGroggy/IsFocusActor) — kept as unit variant
///   tag 221 (CheckAttackImpulseLevel) — added to Class A skip-list;
///                                  vtable[19]=0x1402D3A80 (Win-IDA)
///   tag 261 (CheckDamageElementalType) — added to Class A skip-list;
///                                  vtable[19]=0x1402D3A80 (Win-IDA)
///   tag 286 (CheckCurrentEquipType_OrTag286) — upgraded unit →
///                                  TwoU32BodyPayload; vtable[16]
///                                  0x141C98F40 reads 2×u32 (Win-IDA)
///
/// Verification template for any next promote: read vtable[16] and
/// vtable[19] from the matching `??_7ConditionData_<Name>@pa@@6B@`
/// RTTI symbol. `vtable[16] = 0x141C9A550` reads 1 byte ⇒
/// OneByteBodyPayload. `vtable[19] = 0x141C8D560` is the standard
/// option_block reader (NOT skip). `vtable[19] = 0x1402D3A80` is the
/// no-op (Class A skip).
///
/// Three classes of skip variant exist:
///   A. **vtable[19] = `0x1402D3A80` (literal `return 1;` no-op)**.
///      Win-IDA verified: read the qword at `<vtable>+0x98` from each
///      `??_7ConditionData_<class>@pa@@6B@`. If it's `0x1402D3A80`,
///      the variant unambiguously consumes zero bytes for option_block.
///   B. **vtable[19] = thunk into `sub_14F0D...` / `sub_14F24...`
///      (anti-disassembly obfuscated runtime)**. Byte-math verified:
///      vanilla `case(1)+tag(2)+body+footer(3)` adds up exactly with
///      NO option_block byte. The obfuscated reader behaves like a
///      no-op for these tags.
///   C. **vtable[19] = `0x1413B89E0` (a thunk inside the giant
///      `sub_14139AE80` runtime, size 0x1dc88)**. Empirically observed
///      to consume zero bytes for these tags during interaction_info
///      decode, but Hex-Rays cannot decompile the runtime to confirm.
///      LAST_ATTEMPTED_TAG diagnostic pointed at these — risk: may
///      mask real failures elsewhere in the chain.
fn variant_skips_option_block(tag: u16) -> bool {
    matches!(tag,
        // Class A — vtable[19] = 0x1402D3A80 (literal no-op). Win-IDA
        // verified this session by reading `<vtable>+0x98`:
        //   tag   2: ConditionData_CheckNone           @ 0x144cdd680
        //   tag  81: ConditionData_QuestGaugePercent   @ 0x144ce3038
        //   tag 126: ConditionData_SpecialModeKey      @ 0x144ce1420
        //   tag 256: ConditionData_Macro               @ 0x144ce2f88
        //   tag 272: ConditionData_GameEventParam      @ 0x144ce4cb0
        //   tag 300: vftable @ off_144CD3778
        2 | 81 | 126 | 222 | 257 | 262 | 273 | 301 |
        // Class A (continuing) — same source, vtable[19] = no-op:
        //   tag 221: ConditionData_CheckAttackImpulseLevel  @ 0x144ce5268
        //   tag 261: ConditionData_CheckDamageElementalType @ 0x144ce4080
        307 | 402 |
        // Class B — vtable[19] = thunk into anti-disassembly runtime
        // (sub_14F0D2550 / sub_14F24B730). Byte-math verified: vanilla
        // `case(1)+tag(2)+body+footer(3)` matches with zero option_block.
        79 | 196 |
        // Class C — empirical add via LAST_ATTEMPTED_TAG diagnostic on
        // interaction_info. vtable[19] = `0x1413B89E0` (thunk in
        // sub_14139AE80, non-decompilable). Verified Win-IDA this
        // session that this is NOT class A — its slot 19 is shared
        // with many tags that genuinely DO read option_block (e.g. tag 0
        // GetLevel has the same thunk and reads option_block normally).
        // Originally 6 entries (26 | 99 | 135 | 174 | 360 | 370); the
        // others were promoted to body+option_block recipes during the
        // 2026-04-30 verification cycle (see docs/STATUS.md
        // "Stream-mode GameCondition" section). Tag 26 alone remains.
        26
    )
}

py_binary_struct! {
    /// Generic CString-only payload — used by variants whose vtable[16]
    /// reads a single CString (length-prefixed UTF-8 string).
    pub struct OneCStringBodyPayload<'a> {
        pub value: CString<'a>,
    }
}

py_binary_struct! {
    /// Generic 4-byte payload — used by variants whose vtable[16] reads a
    /// single u32 field. Auto-emits JSON via the macro.
    pub struct OneU32BodyPayload {
        pub value: u32,
    }
}

py_binary_struct! {
    /// Generic 2-byte payload — single u16 field. Auto-emits JSON.
    pub struct OneU16BodyPayload {
        pub value: u16,
    }
}

py_binary_struct! {
    /// Two-u32 payload (8 bytes total) — used by variants whose body
    /// reader is two consecutive u32 reads (e.g. tag 54
    /// CheckCurrentEquipType: `sub_100FBEB78` on Mac reads u32→+24,
    /// u32→+28). Auto-emits JSON via the macro.
    pub struct TwoU32BodyPayload {
        pub a: u32,
        pub b: u32,
    }
}

py_binary_struct! {
    /// Three-u32 payload (12 bytes total) — used by variants like
    /// CheckEquipType that read three consecutive u32 fields.
    /// Auto-emits JSON via the macro.
    pub struct ThreeU32BodyPayload {
        pub a: u32,
        pub b: u32,
        pub c: u32,
    }
}

py_binary_struct! {
    /// u32 + u16 payload (6 bytes total). Auto-emits JSON.
    pub struct U32U16BodyPayload {
        pub a: u32,
        pub b: u16,
    }
}

py_binary_struct! {
    /// Tag 214 — ConditionData_CheckExistStealItem body.
    /// Mac vfn[17] = `sub_100FF106C` → `sub_10101FB50` reads a u32
    /// count, then count × u16 (each is a `pa::ItemGroupKey`). Wire
    /// shape matches the existing `CArray<u16>` reader used elsewhere.
    pub struct ConditionData_CheckExistStealItemPayload {
        pub item_group_keys: CArray<u16>,
    }
}

py_binary_struct! {
    /// Tag 31 — ConditionData_CheckActionAttribute body.
    /// vtable[16] = sub_14F1A1B20: reads a 16-byte buffer (loop
    /// 1-byte-at-a-time) stored at struct +0x18, then 1 byte at struct
    /// +0x28. Body is therefore 16 bytes + 1 byte = 17 bytes wire size.
    #[allow(non_camel_case_types)]
    pub struct ConditionData_CheckActionAttributePayload {
        pub field_at_24_a: u32,
        pub field_at_24_b: u32,
        pub field_at_24_c: u32,
        pub field_at_24_d: u32,
        pub field_at_40: u8,
    }
}

/// `ConditionDataOptionData` per IDA `sub_14B933930` (called from each
/// variant's vtable[19] when option_present != 0):
///   - CString label (u32 len + N bytes)
///   - u64 qword_a
///   - u8 byte_b, u8 byte_c, u8 byte_d
#[derive(Debug)]
pub struct ConditionDataOptionBlock<'a> {
    pub option_present: u8,
    pub option_data: Option<ConditionDataOptionData<'a>>,
}

impl<'a> ConditionDataOptionBlock<'a> {
    pub fn read_from(data: &'a [u8], offset: &mut usize) -> io::Result<Self> {
        let option_present = u8::read_from(data, offset)?;
        let option_data = if option_present != 0 {
            Some(ConditionDataOptionData::read_from(data, offset)?)
        } else {
            None
        };
        Ok(Self { option_present, option_data })
    }
    pub fn write_to(&self, w: &mut dyn Write) -> io::Result<()> {
        self.option_present.write_to(w)?;
        if self.option_present != 0
            && let Some(d) = &self.option_data {
                d.write_to(w)?;
            }
        Ok(())
    }
    pub fn to_json_dict(&self) -> Map<String, Value> {
        let mut m = Map::new();
        m.insert("option_present".into(), self.option_present.to_json_value());
        m.insert(
            "option_data".into(),
            match &self.option_data {
                Some(d) => Value::Object(d.to_json_dict()),
                None => Value::Null,
            },
        );
        m
    }
    pub fn write_from_json_dict(w: &mut Vec<u8>, obj: &Map<String, Value>) -> io::Result<()> {
        let present_v = json_get_field(obj, "option_present")?;
        let present = present_v.as_u64().ok_or_else(|| io::Error::new(
            io::ErrorKind::InvalidData,
            "ConditionDataOptionBlock.option_present: expected u8",
        ))?;
        if present > u8::MAX as u64 {
            return Err(io::Error::new(io::ErrorKind::InvalidData,
                format!("ConditionDataOptionBlock.option_present: {} out of u8 range", present)));
        }
        w.push(present as u8);
        if present != 0 {
            let data_v = json_get_field(obj, "option_data")?;
            let data_obj = data_v.as_object().ok_or_else(|| io::Error::new(
                io::ErrorKind::InvalidData,
                "ConditionDataOptionBlock.option_data: expected object when option_present!=0",
            ))?;
            ConditionDataOptionData::write_from_json_dict(w, data_obj)?;
        }
        Ok(())
    }
}

/// Full ConditionData record: u16 tag + variant payload + optional
/// option block.
///
/// Stream layout: `[u16 tag][variant_body:N][option_block?]`
///
/// Per the Win-binary dispatcher `sub_141C87CE0`, after construction:
///   - slot 16 (+0x80): reads the variant body
///   - slot 19 (+0x98): either `0x1402D3A80 → return 1;` (no-op) for tag
///     81/272, OR the option_block reader (`sub_141C8D560` style) for
///     other variants — reads u8 option_present, conditionally an
///     ConditionDataOptionData (CString + u64 + 3 u8s).
#[derive(Debug)]
pub struct ConditionData<'a> {
    pub base: ConditionDataBase,
    pub variant: ConditionDataVariant<'a>,
    pub option_block: Option<ConditionDataOptionBlock<'a>>,
}

thread_local! {
    /// Tracks the most-recently-attempted ConditionData tag during decode.
    /// Validators read this when read_from returns Err to identify which
    /// variant's recipe is wrong.
    pub static LAST_ATTEMPTED_TAG: std::cell::Cell<Option<u16>> =
        const { std::cell::Cell::new(None) };

    /// Tracks the chain of (tag, byte_offset_after_body) pairs for the
    /// most recent ConditionData decodes (last 8). When the GameCondition
    /// tree desyncs after a sequence of nested ConditionData reads, this
    /// chain pinpoints which tag's recipe over/under-consumed.
    pub static TAG_TRAIL: std::cell::RefCell<Vec<(u16, usize)>> =
        const { std::cell::RefCell::new(Vec::new()) };
}

impl<'a> ConditionData<'a> {
    pub fn read_from(data: &'a [u8], offset: &mut usize) -> io::Result<Self> {
        let base = ConditionDataBase::read_from(data, offset)?;
        let disc = base.tag;
        LAST_ATTEMPTED_TAG.with(|c| c.set(Some(disc)));
        let variant = ConditionDataVariant::read_from(disc, data, offset)?;
        let option_block = if variant_skips_option_block(disc) {
            None
        } else {
            Some(ConditionDataOptionBlock::read_from(data, offset)?)
        };
        let post_offset = *offset;
        TAG_TRAIL.with(|t| {
            let mut t = t.borrow_mut();
            if t.len() >= 8 { t.remove(0); }
            t.push((disc, post_offset));
        });
        Ok(Self { base, variant, option_block })
    }
    pub fn write_to(&self, w: &mut dyn Write) -> io::Result<()> {
        self.base.write_to(w)?;
        self.variant.write_to(w)?;
        if let Some(b) = &self.option_block {
            b.write_to(w)?;
        }
        Ok(())
    }

    /// JSON shape:
    /// - `base`: { tag: u16 }
    /// - `variant`: { type: variant_name, body?: typed dict } —
    ///   per-variant typed JSON via ConditionDataVariant::to_json_value.
    ///   `body` is present only for payload-bearing variants (218 of
    ///   the 405); pure-discriminator variants emit just `{type}`.
    /// - `option_block`: { option_present, option_data: {...} | null } | null
    ///   (null when the tag's vtable[19] is the no-op, i.e.
    ///   `variant_skips_option_block` returns true).
    pub fn to_json_dict(&self) -> Map<String, Value> {
        let mut m = Map::new();
        m.insert("base".into(), Value::Object(self.base.to_json_dict()));
        m.insert("variant".into(), self.variant.to_json_value());
        m.insert(
            "option_block".into(),
            match &self.option_block {
                Some(b) => Value::Object(b.to_json_dict()),
                None => Value::Null,
            },
        );
        m
    }

    pub fn write_from_json_dict(w: &mut Vec<u8>, obj: &Map<String, Value>) -> io::Result<()> {
        let base_v = json_get_field(obj, "base")?;
        let base_obj = base_v.as_object().ok_or_else(|| {
            io::Error::new(io::ErrorKind::InvalidData, "ConditionData.base: expected object")
        })?;
        let tag = json_get_field(base_obj, "tag")?
            .as_u64()
            .ok_or_else(|| io::Error::new(io::ErrorKind::InvalidData,
                "ConditionData.base.tag: expected u16"))?;
        if tag > u16::MAX as u64 {
            return Err(io::Error::new(io::ErrorKind::InvalidData,
                format!("ConditionData.base.tag: {} out of u16 range", tag)));
        }
        ConditionDataBase::write_from_json_dict(w, base_obj)?;
        let variant_v = json_get_field(obj, "variant")?;
        ConditionDataVariant::write_from_json(tag as u16, w, variant_v)?;
        let opt_v = json_get_field(obj, "option_block")?;
        match opt_v {
            Value::Null => {}
            Value::Object(opt_obj) => {
                ConditionDataOptionBlock::write_from_json_dict(w, opt_obj)?;
            }
            _ => return Err(io::Error::new(
                io::ErrorKind::InvalidData,
                "ConditionData.option_block: expected object or null",
            )),
        }
        Ok(())
    }
}
